def remove_edge(graph, u, v):
    """
    Belirtilen kenarı (u, v) grafikten kaldırır.
    Grafik, komşuluk listesi olarak bir sözlükle temsil edilir.
    Varsayılan olarak yönsüz bir grafik için tasarlanmıştır.

    Parametreler:
        graph (dict): Düğümden komşu düğümlerin listesine eşleyen bir sözlük.
                      Örnek: {'A': ['B', 'C'], 'B': ['A', 'D']}
        u: Kaldırılacak kenarın ilk düğümü.
        v: Kaldırılacak kenarın ikinci düğümü.
    """
    if u in graph and v in graph:
        if v in graph[u]:
            graph[u].remove(v)
        if u in graph[v]:
            graph[v].remove(u)
